	gv := schema.GroupVersion{Group: "example.com", Version: "v1"}
	config.GroupVersion = &gv
	config.APIPath = "/apis"
	config.NegotiatedSerializer = rest.CodecFactoryForGeneratedClient(runtime.NewScheme(), nil).WithoutConversion()

